38	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const ENCHANTMENT_THRESHOLD = 5;
40	
41	function calculateItemSurcharges(items: any[]): number {
42	  let total = 0;
43	  for (const item of items) {
44	    const base = BASE_PREMIUM[item.type] ?? 0;
45	    if (item.cursed) {
46	      total += base * CURSED_SURCHARGE_RATE;
47	    }
48	    if ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD) {
49	      total += base * ENCHANTMENT_SURCHARGE_RATE;
50	    }
51	  }
52	  return total;
53	}
54	
55	function calculateQuotePremium(items: any[]): number {
56	  const typeCounts = countByType(items);
57	  const basePremium = calculateBasePremium(typeCounts);
58	  const itemSurcharges = calculateItemSurcharges(items);
59	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
60	  return Math.ceil(basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE);
61	}
62	
63	export function processScenario(scenario: any): unknown {
64	  const results = scenario.steps.map((step: any) => ({
65	    premium: calculateQuotePremium(step.items),
66	  }));
67	
68	  return { results };
69	}
